import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';

function Login({ setToken }) {
  const [credentials, setCredentials] = useState({ username: 'admin', password: 'admin123' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');
    try {
      const response = await axios.post('/api/admin/login', credentials);
      localStorage.setItem('adminToken', response.data.token);
      setToken(response.data.token);
      navigate('/dashboard');
    } catch (err) {
      setError(err.response?.data?.error || 'Login failed');
    }
    setLoading(false);
  };

  return (
    <div className="login-container">
      <div className="row justify-content-center">
        <div className="col-11 col-md-6 col-lg-5">
          <div className="login-card">
<div className="text-center mb-4 pb-4">

              <h1 className="h3 fw-bold mb-2">Vyntex Admin</h1>
              <p className="text-muted lead">Sign in to your dashboard</p>
            </div>
            <form onSubmit={handleSubmit}>
              <div className="mb-4">
<div className="form-floating mb-4">
                  <input
                    type="text"
                    className="form-control form-control-lg"
                    id="username"
                    placeholder="admin"
                    value={credentials.username}
                    onChange={(e) => setCredentials({...credentials, username: e.target.value})}
                    autoFocus
                  />
                  <label htmlFor="username">Username</label>
                </div>
              </div>
              <div className="mb-4">
<div className="form-floating mb-4">
                  <input
                    type="password"
                    className="form-control form-control-lg"
                    id="password"
                    placeholder="admin123"
                    value={credentials.password}
                    onChange={(e) => setCredentials({...credentials, password: e.target.value})}
                  />
                  <label htmlFor="password">Password</label>
                </div>
              </div>
              {error && <div className="alert alert-danger alert-dismissible fade show" role="alert">
                {error} <button type="button" className="btn-close" onClick={() => setError('')}></button>
              </div>}
              <button type="submit" className="btn btn-primary btn-lg w-100 py-3 mb-3" disabled={loading}>
                {loading ? <><i className="bi bi-hourglass-split me-2 spinner-border spinner-border-sm"></i>Loading...</> : 'Sign In'}
              </button>
            </form>
            <div className="text-center">
              <small className="text-muted">Default: <strong>admin / admin123</strong></small>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Login;
